import{_ as t,c as s,o as a,ah as o}from"./chunks/framework.RCw5T9E9.js";const p=JSON.parse('{"title":"Advanced capture mode","description":"","frontmatter":{"title":"Advanced capture mode"},"headers":[],"relativePath":"network/advanced.md","filePath":"network/advanced.md"}'),n={name:"network/advanced.md"};function r(i,e,d,l,h,c){return a(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="advanced-capture-mode" tabindex="-1">Advanced capture mode <a class="header-anchor" href="#advanced-capture-mode" aria-label="Permalink to &quot;Advanced capture mode&quot;">​</a></h1><p>Under <strong>Options → Network</strong> you can choose the <strong>capture mode</strong> for network traffic:</p><table tabindex="0"><thead><tr><th>Mode</th><th>In the UI</th><th>What it means</th></tr></thead><tbody><tr><td><strong>Classic mode</strong></td><td>classic snapshot</td><td>Same limits as in-page interception: headers and bodies are only what page scripts can read (including <strong>CORS</strong> rules for cross-origin). See <a href="./general.html#display-limits">Working with requests</a>.</td></tr><tr><td><strong>Advanced mode</strong></td><td>extended capture</td><td>The extension requests <strong><code>webRequest</code></strong> access and enriches the request details with the <strong>full set</strong> of request and response headers as seen by the browser for the exchange—not only the subset exposed to the page.</td></tr></tbody></table><p>Turning on <strong>Advanced mode</strong> and related features (pinning headers, <strong>Header links</strong>, editing rules with <strong>Extract regex</strong> and <strong>Transform</strong>) is available <strong>only in the Chrome / Edge extension</strong>.<br><strong>Standalone</strong> still runs without extended capture: the full header set via <strong><code>webRequest</code></strong> described below <strong>is not available</strong> there.</p><hr><h2 id="what-advanced-mode-adds-in-the-network-tab" tabindex="-1">What Advanced mode adds in the Network tab <a class="header-anchor" href="#what-advanced-mode-adds-in-the-network-tab" aria-label="Permalink to &quot;What Advanced mode adds in the Network tab&quot;">​</a></h2><ul><li><strong>Request and response headers</strong> in request details use the extended data (including headers not listed in <code>Access-Control-Expose-Headers</code>).</li><li><strong>Pinning header rows</strong> — a header name can be pinned <strong>to the top of the list</strong> separately for <strong>Request</strong> and <strong>Response</strong>. Pins are toggled from the <strong>row menu</strong> (three dots) when Advanced mode is on.</li><li><strong>Header links</strong> — a rule meaning “for this header on this host, open an external URL”; the template substitutes a processed value for the <code>{value}</code> placeholder.</li></ul><p>The <strong>Header links</strong> list and <strong>Pinned headers</strong> table under <strong>Options → Network</strong> are shown <strong>only when Advanced mode is enabled</strong>, so Classic mode stays uncluttered.</p><hr><h2 id="header-links" tabindex="-1">Header links <a class="header-anchor" href="#header-links" aria-label="Permalink to &quot;Header links&quot;">​</a></h2><p>Each rule defines:</p><ul><li><strong>Header</strong> — HTTP header name (matched <strong>case-insensitively</strong>);</li><li><strong>Host</strong> — host of the request URL (normalized: no scheme or path, e.g. <code>api.example.com</code>);</li><li><strong>Link</strong> — URL template where <strong><code>{value}</code></strong> is replaced by the <strong>final string</strong> after extract and transform (see below).</li></ul><p>You can create and edit rules from the <strong>header row menu</strong> on the <strong>Network</strong> tab (Advanced) and from <strong>Options</strong> when a header rule group is selected.</p><p><strong><code>{value}</code></strong> is built as follows:</p><ol><li>Start from the <strong>raw</strong> header value shown on the request card.</li><li>Optionally apply <strong>Extract regex</strong> (if the field is set).</li><li>Optionally apply a <strong>Transform</strong> chain (if the field is set).</li><li>Substitute the result into every <strong><code>{value}</code></strong> in the link template.</li></ol><p><strong>Extract regex</strong> and <strong>Transform</strong> are <strong>independent</strong>: you can set regex only, transform only, or both.</p><hr><h2 id="extract-regex" tabindex="-1">Extract regex <a class="header-anchor" href="#extract-regex" aria-label="Permalink to &quot;Extract regex&quot;">​</a></h2><ul><li>The string is used as the <strong>pattern</strong> for <strong><code>new RegExp(pattern)</code></strong> (no separate flags argument; if you need flags, they must be expressible in the pattern string where syntax allows).</li><li><strong><code>String.prototype.match</code></strong> runs on the <strong>raw</strong> header value.</li><li>If there is a <strong>first capturing group</strong> in the match, <strong>that</strong> substring is passed on.</li><li>If there are no groups, the <strong>full match</strong> is used.</li><li>If the pattern is <strong>invalid</strong> or there is <strong>no match</strong>, the <strong>original</strong> header value is used for the next step (as if regex were skipped).</li></ul><h3 id="sample-patterns" tabindex="-1">Sample patterns <a class="header-anchor" href="#sample-patterns" aria-label="Permalink to &quot;Sample patterns&quot;">​</a></h3><div class="language-regex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">regex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">([a-f0-9-]</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">)</span></span></code></pre></div><div class="language-regex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">regex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">(\\d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">)</span></span></code></pre></div><div class="language-regex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">regex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#DBEDFF;">https</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?</span><span style="--shiki-light:#032F62;--shiki-dark:#DBEDFF;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\/\\/([</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">^</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\/]</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">)</span></span></code></pre></div><hr><h2 id="transform" tabindex="-1">Transform <a class="header-anchor" href="#transform" aria-label="Permalink to &quot;Transform&quot;">​</a></h2><p>The <strong>Transform</strong> string is a pipeline of steps separated by <strong><code>|</code></strong>. Steps run <strong>left to right</strong>; each step receives the previous output.</p><p>Each step is a “function” call:</p><table tabindex="0"><thead><tr><th>Function</th><th>Purpose</th><th>Example</th></tr></thead><tbody><tr><td><strong><code>trim()</code></strong></td><td>Trim leading and trailing whitespace</td><td><code>&quot; abc &quot;</code> → <code>&quot;abc&quot;</code></td></tr><tr><td><strong><code>lowercase()</code></strong></td><td>Lower case</td><td><code>ABC</code> → <code>abc</code></td></tr><tr><td><strong><code>uppercase()</code></strong></td><td>Upper case</td><td><code>abc</code> → <code>ABC</code></td></tr><tr><td><strong><code>replace(&quot;a&quot;,&quot;b&quot;)</code></strong></td><td>Replace every occurrence of substring <strong>a</strong> with <strong>b</strong></td><td><code>replace(&quot;-&quot;, &quot;&quot;)</code></td></tr><tr><td><strong><code>substring(start,end)</code></strong></td><td>Slice like <strong><code>String.prototype.slice(start, end)</code></strong></td><td><code>substring(0, 8)</code></td></tr><tr><td><strong><code>removeNonDigits()</code></strong></td><td>Keep digits only</td><td><code>+54 (11) 5555</code> → <code>54115555</code></td></tr><tr><td><strong><code>prefix(&quot;x&quot;)</code></strong></td><td>Prefix</td><td><code>prefix(&quot;id-&quot;)</code></td></tr><tr><td><strong><code>suffix(&quot;x&quot;)</code></strong></td><td>Suffix</td><td><code>suffix(&quot;-prod&quot;)</code></td></tr></tbody></table><p>Arguments for <strong><code>replace</code></strong>, <strong><code>prefix</code></strong>, and <strong><code>suffix</code></strong> use <strong>double</strong> or <strong>single</strong> quotes. Inside a string, <strong><code>\\\\</code></strong> escapes the next character.</p><p>An unknown “function” name or bad argument count for <strong>substring</strong> / <strong>replace</strong> means <strong>that step is skipped</strong> (the value for the next step is unchanged by that step).</p><h3 id="placeholder-and-hints" tabindex="-1">Placeholder and hints <a class="header-anchor" href="#placeholder-and-hints" aria-label="Permalink to &quot;Placeholder and hints&quot;">​</a></h3><p>Typical chained example:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>replace(&quot;-&quot;, &quot;&quot;) | lowercase()</span></span></code></pre></div><p>Short examples: <strong><code>trim()</code></strong>, <strong><code>lowercase()</code></strong>, <strong><code>replace(&quot;-&quot;, &quot;&quot;)</code></strong>.</p><hr><h2 id="end-to-end-examples" tabindex="-1">End-to-end examples <a class="header-anchor" href="#end-to-end-examples" aria-label="Permalink to &quot;End-to-end examples&quot;">​</a></h2><h3 id="normalize-a-uuid" tabindex="-1">Normalize a UUID <a class="header-anchor" href="#normalize-a-uuid" aria-label="Permalink to &quot;Normalize a UUID&quot;">​</a></h3><p><strong>Extract regex:</strong></p><div class="language-regex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">regex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">([a-f0-9-]</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">{36}</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">)</span></span></code></pre></div><p><strong>Transform:</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>replace(&quot;-&quot;, &quot;&quot;)</span></span></code></pre></div><p><strong>Value substituted for <code>{value}</code>:</strong> hex string without hyphens, e.g. <code>fbdb0effcaf44d4d86652a71f5556274</code>.</p><h3 id="extract-a-numeric-id" tabindex="-1">Extract a numeric id <a class="header-anchor" href="#extract-a-numeric-id" aria-label="Permalink to &quot;Extract a numeric id&quot;">​</a></h3><p><strong>Extract regex:</strong></p><div class="language-regex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">regex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">(\\d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">)</span></span></code></pre></div><p><strong>Transform:</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>trim()</span></span></code></pre></div><h3 id="lowercase-the-whole-header" tabindex="-1">Lowercase the whole header <a class="header-anchor" href="#lowercase-the-whole-header" aria-label="Permalink to &quot;Lowercase the whole header&quot;">​</a></h3><p><strong>Extract regex:</strong></p><div class="language-regex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">regex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">(.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">)</span></span></code></pre></div><p><strong>Transform:</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>trim() | lowercase()</span></span></code></pre></div><hr><h2 id="quick-recap" tabindex="-1">Quick recap <a class="header-anchor" href="#quick-recap" aria-label="Permalink to &quot;Quick recap&quot;">​</a></h2><ul><li><strong>Advanced mode</strong> extends headers via <strong><code>webRequest</code></strong>; <strong>Standalone</strong> does not provide this mode.</li><li><strong>Classic mode</strong> is the original “page-visible” header model.</li><li><strong>Pin</strong> — separate for <strong>Request</strong> / <strong>Response</strong> lists.</li><li><strong>Header links:</strong> template with <strong><code>{value}</code></strong>, optional <strong>Extract regex</strong>, then <strong>Transform</strong> (chain with <code>|</code>).</li></ul>',55)])])}const u=t(n,[["render",r]]);export{p as __pageData,u as default};
